```
#include <iostream>
#include <вектор>

std::vector<int> findLongestIncreasingSequence(const std::vector<int>& vec) {
    int n = vec.size();
    std::вектор<int> dp(n, 1), prev(n, -1);
    int bestIndex = 0, bestLength = 1;

    за (int i = 1; i < n; i++) {
        за (int j = 0; j < i; j++) {
            ако (vec[j] < vec[i] && dp[j] + 1 > dp[i]) {
                dp[i] = dp[j] + 1;
                prev[i] = j;
            }
        }
        ако (dp[i] > најдобра должина) {
            најдобарИндекс = i;
            најдобра должина = dp[i];
        }
    }

    std::vector<int> ret;
    за (int i = 0; i < bestLength; i++) {
        ret.push_back(vec[bestIndex]);
        bestIndex = prev[bestIndex];
    }
    std::reverse(ret.begin(), ret.end());
    враќање ret;
}
```

Функцијата зема `std::vector<int>` како аргумент и враќа друг `std::vector<int>` кој ги содржи елементите од најдолгата растечка подсеквенца. Тој користи динамично програмирање, зачувувајќи ја должината на најдолгата последователна низа што завршува на секој индекс, како и индексот на претходниот елемент во последователната низа. Потоа се следи назад од последниот елемент од најдолгата последователна секвенца за да ја конструира самата потсеквенца.
